import React, { useState } from 'react';
import { 
  TrendingUp, Users, ArrowUpRight, 
  Activity, Zap, Download, CheckCircle 
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

export default function Analytics() {
  const [showToast, setShowToast] = useState(false);

  // Stats data
  const stats = [
    { label: 'Active Users', value: '2.4k', growth: '+12%', icon: <Users size={20}/> },
    { label: 'Total Barters', value: '842', growth: '+18%', icon: <Activity size={20}/> },
    { label: 'Success Rate', value: '94%', growth: '+2%', icon: <Zap size={20}/> },
  ];

  // Logic for Export Button
  const handleExport = () => {
    // Simulating a CSV download
    const reportData = "Date,UserActivity,Barters\n2026-01-01,1200,45\n2026-01-02,1500,60";
    const blob = new Blob([reportData], { type: 'text/csv' });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.setAttribute('hidden', '');
    a.setAttribute('href', url);
    a.setAttribute('download', 'wertech_analytics_report.csv');
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);

    // Show success feedback
    setShowToast(true);
    setTimeout(() => setShowToast(false), 3000);
  };

  return (
    <div className="p-10 max-w-7xl mx-auto space-y-10">
      
      {/* HEADER */}
      <div className="flex justify-between items-end">
        <div>
          <h1 className="text-4xl font-black text-slate-800 tracking-tighter uppercase italic">Analytics</h1>
          <p className="text-slate-400 font-bold text-[10px] tracking-[0.2em] mt-1 uppercase">Usage Patterns & Growth</p>
        </div>
        <button 
          onClick={handleExport}
          className="px-6 py-4 bg-slate-900 text-white rounded-[20px] font-black text-[10px] uppercase tracking-widest flex items-center gap-2 shadow-xl hover:bg-teal-600 transition-all active:scale-95"
        >
          <Download size={16} /> Export Report
        </button>
      </div>

      {/* TOP STAT CARDS */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {stats.map((stat, i) => (
          <div key={i} className="bg-white p-8 rounded-[40px] border border-slate-50 shadow-sm flex items-center justify-between">
            <div>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{stat.label}</p>
              <h3 className="text-3xl font-black text-slate-800">{stat.value}</h3>
              <div className="flex items-center gap-1 mt-2 text-teal-600 font-black text-[10px]">
                <ArrowUpRight size={14} /> {stat.growth}
              </div>
            </div>
            <div className="p-5 bg-teal-50 text-teal-600 rounded-3xl">
              {stat.icon}
            </div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        
        {/* FIXED ACTIVITY TRENDS GRAPH */}
        <div className="lg:col-span-8 bg-white rounded-[40px] p-10 border border-slate-50 shadow-sm">
          <div className="flex justify-between items-center mb-12">
            <h3 className="text-xl font-black text-slate-800 flex items-center gap-3">
              <TrendingUp className="text-teal-600" /> Activity Trends
            </h3>
            <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest bg-slate-50 px-4 py-2 rounded-full">
              Last 7 Days
            </div>
          </div>
          
          {/* VISIBLE BAR GRAPH */}
          <div className="h-72 w-full flex items-end justify-between gap-4 px-2">
            {[55, 85, 40, 100, 75, 90, 65].map((height, i) => (
              <div key={i} className="flex-1 flex flex-col items-center gap-4 group">
                {/* The Bar */}
                <motion.div 
                  initial={{ height: 0 }}
                  animate={{ height: `${height}%` }}
                  transition={{ duration: 1, delay: i * 0.1 }}
                  className="w-full bg-slate-100 group-hover:bg-teal-600 rounded-2xl transition-all duration-300 relative cursor-pointer"
                >
                  {/* Tooltip on hover */}
                  <div className="absolute -top-10 left-1/2 -translate-x-1/2 bg-slate-900 text-white text-[10px] font-bold px-3 py-1 rounded-lg opacity-0 group-hover:opacity-100 transition-opacity">
                    {height * 15}
                  </div>
                </motion.div>
                <span className="text-[10px] font-black text-slate-300 uppercase">Day {i+1}</span>
              </div>
            ))}
          </div>
        </div>

        {/* SYSTEM PULSE LOG */}
        <div className="lg:col-span-4 bg-white rounded-[40px] p-10 border border-slate-50 shadow-sm">
          <h3 className="text-xl font-black text-slate-800 mb-8">System Pulse</h3>
          <div className="space-y-8">
            {[
              { user: 'Rahul K.', action: 'New Barter', time: '2M AGO' },
              { user: 'Gouri', action: 'Accepted Request', time: '15M AGO' },
              { user: 'Admin', action: 'System Update', time: '1H AGO' },
              { user: 'Suresh V.', action: 'Joined', time: '3H AGO' },
            ].map((log, i) => (
              <div key={i} className="flex items-center gap-4">
                <div className="w-2.5 h-2.5 rounded-full bg-teal-500 shadow-[0_0_10px_rgba(20,184,166,0.4)]" />
                <div className="flex-1">
                  <p className="text-xs font-black text-slate-800 leading-none">{log.user}</p>
                  <p className="text-[9px] font-black text-slate-400 uppercase mt-1">{log.action}</p>
                </div>
                <span className="text-[9px] font-black text-slate-300">{log.time}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* EXPORT SUCCESS TOAST */}
      <AnimatePresence>
        {showToast && (
          <motion.div 
            initial={{ y: 100, opacity: 0 }}
            animate={{ y: 0, opacity: 1 }}
            exit={{ y: 100, opacity: 0 }}
            className="fixed bottom-10 right-10 bg-slate-900 text-white px-8 py-4 rounded-[20px] shadow-2xl flex items-center gap-3 z-50"
          >
            <CheckCircle className="text-teal-400" size={20} />
            <span className="font-black uppercase text-[10px] tracking-widest">Report Downloaded</span>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}
